impl Solution { pub fn smallest_equivalent_string(black_s1: String, black_s2: String, black_b: String) -> String { let mut black_f: Vec<u8> = (0..26).collect(); fn black_find(i: u8, f: &mut Vec<u8>) -> u8 { if f[i as usize] == i { i } else { f[i as usize] = black_find(f[i as usize], f); f[i as usize] } } for (c1, c2) in black_s1.bytes().zip(black_s2.bytes()) { let (r1, r2) = (black_find(c1 - b'a', &mut black_f), black_find(c2 - b'a', &mut black_f)); if r1 < r2 { black_f[r2 as usize] = r1; } else if r2 < r1 { black_f[r1 as usize] = r2; } } black_b.bytes().map(|c| (black_find(c - b'a', &mut black_f) + b'a') as char).collect() } }